import socket
from threading import Thread
import json

class GameServer:
    def __init__(self):
        self.server_socket = None
        self.player_list = []
        self.game_state = {}
        self.lock = Thread()

    def start_server(self, host='0.0.0.0', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((host, port))
        print(f"Server started on {host}:{port}")

        thread = Thread(target=self.listen_for_queries)
        thread.daemon = True
        thread.start()

    def listen_for_queries(self):
        while True:
            data, address = self.server_socket.recvfrom(1024)
            if data.decode() == "status":
                response = self.get_server_status()
                self.send_response(address, response)

    def get_server_status(self):
        return {
            'player_list': self.player_list,
            'game_state': self.game_state
        }

    def send_response(self, address, data):
        try:
            self.server_socket.sendto(json.dumps(data).encode(), address)
        except Exception as e:
            print(f"Error sending response: {e}")

    def add_player(self, player_name):
        with self.lock:
            self.player_list.append(player_name)

    def remove_player(self, player_name):
        with self.lock:
            if player_name in self.player_list:
                self.player_list.remove(player_name)

    def update_game_state(self, game_state):
        with self.lock:
            self.game_state = game_state

def main():
    server = GameServer()
    server.start_server()

if __name__ == "__main__":
    main()